const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const quoteStep = ({ items }: Step) => {
  const base = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
  return { premium: Math.ceil(base + firstInsuranceSurcharge + PROCESSING_FEE) };
};

export const runScenario = (input: Scenario): unknown => ({
  results: input.steps.map(quoteStep),
});
